/**
 * chartUtils.js
 * Builds Highcharts configuration objects from backend query result data.
 * Supports bar, line, and pie chart types with a premium dark theme.
 */

// ── Colour palette ────────────────────────────────────────────────────────
const PALETTE = [
  '#22d3ee', '#8b5cf6', '#10b981', '#f59e0b',
  '#f43f5e', '#3b82f6', '#a78bfa', '#34d399',
  '#fbbf24', '#06b6d4', '#ec4899', '#84cc16',
];

// ── Base Highcharts theme ─────────────────────────────────────────────────
const BASE_THEME = {
  chart: {
    backgroundColor: 'transparent',
    style: { fontFamily: "'Inter', sans-serif" },
    spacing: [12, 12, 12, 12],
    animation: { duration: 600 },
  },
  title:  { text: null },
  credits: { enabled: false },
  colors:  PALETTE,
  legend: {
    itemStyle:      { color: '#94a3b8', fontWeight: '400', fontSize: '12px' },
    itemHoverStyle: { color: '#f0f6ff' },
  },
  tooltip: {
    backgroundColor: '#0f2040',
    borderColor:     'rgba(255,255,255,0.1)',
    borderRadius:    10,
    shadow:          false,
    style:           { color: '#f0f6ff', fontSize: '13px' },
  },
  exporting: { enabled: false },
};

const AXIS_STYLE = {
  labels: { style: { color: '#94a3b8', fontSize: '11px' } },
  lineColor:     'rgba(255,255,255,0.06)',
  tickColor:     'rgba(255,255,255,0.06)',
  gridLineColor: 'rgba(255,255,255,0.05)',
};

// ── Axis detection ────────────────────────────────────────────────────────

/**
 * Detect category column (first string column) and numeric value columns.
 * Returns { catKey, valKeys[] }
 */
function detectAxes(data, columns = []) {
  if (!data || !data.length) return { catKey: null, valKeys: [] };

  const keys   = columns.length ? columns : Object.keys(data[0]);
  const sample = data.slice(0, 20);

  const isNum = (k) => sample.every(r => r[k] === null || r[k] === undefined || typeof r[k] === 'number');

  let catKey  = null;
  const valKeys = [];

  for (const k of keys) {
    if (!catKey && !isNum(k)) {
      catKey = k;
    } else if (isNum(k) && valKeys.length < 5) {
      valKeys.push(k);
    }
  }

  // Fallback: all numeric — treat first as category
  if (!catKey && valKeys.length > 0) catKey = valKeys.shift();

  return { catKey, valKeys };
}

/** snake_case → Title Case */
function fmtLabel(key = '') {
  return key.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase());
}

/** Safe number coercion */
function toNum(v) {
  if (v === null || v === undefined) return null;
  const n = Number(v);
  return isFinite(n) ? parseFloat(n.toFixed(4)) : null;
}

// ── Bar chart ─────────────────────────────────────────────────────────────
function buildBarConfig(data, title = '') {
  const { catKey, valKeys } = detectAxes(data);
  if (!catKey || !valKeys.length) return null;

  const categories = data.map(r => String(r[catKey] ?? ''));
  const isMulti    = valKeys.length > 1;

  const series = valKeys.map((k, i) => ({
    name:  fmtLabel(k),
    type:  'bar',
    data:  data.map(r => toNum(r[k])),
    color: PALETTE[i % PALETTE.length],
    borderRadius: 4,
    dataLabels: {
      enabled:   !isMulti,
      style:     { color: '#f0f6ff', fontSize: '11px', textOutline: 'none', fontWeight: '400' },
      formatter() {
        const v = this.y;
        if (v === null) return '';
        return v >= 1000000 ? `${(v / 1000000).toFixed(1)}M`
          : v >= 1000 ? `${(v / 1000).toFixed(1)}k`
          : v.toFixed(1);
      },
    },
  }));

  return {
    ...BASE_THEME,
    chart: { ...BASE_THEME.chart, type: 'bar' },
    title: { text: title, style: { color: '#94a3b8', fontSize: '12px' } },
    xAxis: {
      categories,
      ...AXIS_STYLE,
      labels: {
        ...AXIS_STYLE.labels,
        formatter() {
          const v = String(this.value);
          return v.length > 22 ? v.slice(0, 20) + '…' : v;
        },
      },
    },
    yAxis: {
      title: { text: isMulti ? null : fmtLabel(valKeys[0]), style: { color: '#475569' } },
      ...AXIS_STYLE,
    },
    plotOptions: {
      bar: { stacking: valKeys.length > 2 ? 'normal' : undefined, groupPadding: 0.1, pointPadding: 0.05 },
    },
    legend: { ...BASE_THEME.legend, enabled: isMulti },
    series,
  };
}

// ── Line chart ────────────────────────────────────────────────────────────
function buildLineConfig(data, title = '') {
  const { catKey, valKeys } = detectAxes(data);
  if (!catKey || !valKeys.length) return null;

  const categories = data.map(r => String(r[catKey] ?? ''));

  const series = valKeys.map((k, i) => ({
    name:  fmtLabel(k),
    type:  'spline',
    data:  data.map(r => toNum(r[k])),
    color: PALETTE[i % PALETTE.length],
    lineWidth: 2.5,
    marker: { enabled: data.length <= 40, radius: 4, symbol: 'circle' },
    ...(i === 0 ? {
      fillColor: {
        linearGradient: { x1: 0, y1: 0, x2: 0, y2: 1 },
        stops: [
          [0, `${PALETTE[0]}33`],
          [1, `${PALETTE[0]}00`],
        ],
      },
      type: 'areaspline',
      fillOpacity: 0.15,
    } : {}),
  }));

  return {
    ...BASE_THEME,
    chart: { ...BASE_THEME.chart, type: 'spline' },
    title: { text: title, style: { color: '#94a3b8', fontSize: '12px' } },
    xAxis: {
      categories,
      ...AXIS_STYLE,
      labels: {
        ...AXIS_STYLE.labels,
        rotation: data.length > 12 ? -30 : 0,
        formatter() {
          const v = String(this.value);
          return data.length > 20 && v.length > 7 ? v.slice(0, 6) + '…' : v;
        },
      },
    },
    yAxis: {
      title: { text: valKeys.length === 1 ? fmtLabel(valKeys[0]) : null, style: { color: '#475569' } },
      ...AXIS_STYLE,
    },
    plotOptions: { series: { connectNulls: true } },
    legend: { ...BASE_THEME.legend, enabled: valKeys.length > 1 },
    series,
  };
}

// ── Pie chart ─────────────────────────────────────────────────────────────
function buildPieConfig(data, title = '') {
  const { catKey, valKeys } = detectAxes(data);
  if (!catKey || !valKeys.length) return null;

  const valKey = valKeys[0];
  const sorted = [...data]
    .map(r => ({ name: String(r[catKey] ?? ''), y: toNum(r[valKey]) || 0 }))
    .filter(p => p.y > 0)
    .sort((a, b) => b.y - a.y);

  // Collapse tail beyond 10 slices
  let pieData = sorted;
  if (sorted.length > 10) {
    const top   = sorted.slice(0, 10);
    const other = sorted.slice(10).reduce((acc, p) => acc + p.y, 0);
    pieData = [...top, { name: 'Other', y: other, color: '#334155' }];
  }

  pieData = pieData.map((p, i) => ({ ...p, color: p.color ?? PALETTE[i % PALETTE.length] }));

  return {
    ...BASE_THEME,
    chart: { ...BASE_THEME.chart, type: 'pie' },
    title: { text: title, style: { color: '#94a3b8', fontSize: '12px' } },
    plotOptions: {
      pie: {
        innerSize:        '40%',
        borderColor:      '#020817',
        borderWidth:      2,
        allowPointSelect: true,
        cursor:           'pointer',
        dataLabels: {
          enabled:  true,
          distance: 16,
          format:   '<span style="color:{point.color};font-family:JetBrains Mono,monospace;font-size:11px">{point.name}</span><br/><b>{point.percentage:.1f}%</b>',
          style:    { color: '#f0f6ff', fontSize: '11px', textOutline: 'none', fontWeight: '400' },
          connectorColor: 'rgba(255,255,255,0.15)',
        },
        showInLegend: data.length > 6,
      },
    },
    legend: { ...BASE_THEME.legend, enabled: data.length > 6, maxHeight: 80 },
    series: [{ name: fmtLabel(valKey), data: pieData }],
  };
}

// ── Dispatcher ─────────────────────────────────────────────────────────────
export function buildChartConfig(chartType, data, question = '') {
  if (!Array.isArray(data) || !data.length) return null;

  const title = question.length > 55 ? question.slice(0, 52) + '…' : question;

  switch (chartType) {
    case 'bar':  return buildBarConfig(data, title);
    case 'line': return buildLineConfig(data, title);
    case 'pie':  return buildPieConfig(data, title);
    default:     return null;
  }
}

export { buildBarConfig, buildLineConfig, buildPieConfig };
